192	<body>
193	  <header>
194	    <span class="title">NAS Sync Settings &mdash; POP Creations</span>
195	    <a href="/accounts/logout/" class="logout">Sign out</a>
196	  </header>
197	
198	  <main>
199	    <nav class="page-nav">
200	      <a href="{{ url_for('index') }}" class="nav-tab">Settings</a>
201	      <a href="{{ url_for('status_page') }}" class="nav-tab active">Sync Status</a>
202	    </nav>
203	
204	    <h1 class="page-heading">Sync Status</h1>
205	    <p class="page-sub">Live status from the seaf-cli containers. Updates every 10 seconds.</p>
206	
207	    <div id="cards">
208	      {% for lib in libraries %}
209	      <div class="card" id="card-{{ lib.id }}">
210	        <div class="card-header">
211	          <div class="card-header-left">
212	            <h2>{{ lib.name }}</h2>
213	            <span class="uuid">{{ lib.uuid }}</span>
214	          </div>
215	          <div class="last-seen" id="seen-{{ lib.id }}">Waiting for first report…</div>
216	        </div>
217	        <div id="body-{{ lib.id }}">
218	          <div class="no-data">No data yet. Container may be starting up.</div>
219	        </div>
220	      </div>
221	      {% endfor %}
222	    </div>
223	
224	    <p class="refresh-note" id="refresh-note">Refreshing…</p>
225	  </main>
226	
227	  <script>
228	    const LIBRARIES = {{ libraries | tojson }};
229	
230	    function ago(seconds) {
231	      if (seconds === null || seconds === undefined) return "unknown";
232	      if (seconds < 5)  return "just now";
233	      if (seconds < 60) return seconds + "s ago";
234	      if (seconds < 3600) return Math.floor(seconds / 60) + "m ago";
235	      return Math.floor(seconds / 3600) + "h ago";
236	    }
237	
238	    function fmtFiles(n) {
239	      if (n === null || n === undefined) return "—";
240	      return n.toLocaleString();
241	    }
242	
243	    function fmtIngestDays(d) {
244	      if (d === null || d === undefined) return "—";
245	      if (d === 0) return "All files";
246	      return d + " days";
247	    }
248	
249	    function badgeClass(state, stale) {
250	      if (stale) return "idle";
251	      if (state === "synchronized") return "ok";
252	      if (state === "uploading" || state === "downloading") return "busy";
253	      if (state === "error") return "error";
254	      return "idle";
255	    }
256	
257	    function badgeLabel(entry, state, stale) {
258	      if (stale) return "Offline";
259	      if (!entry.daemon_alive) return "Daemon stopped";
260	      if (state === "synchronized") return "Synchronized";
261	      if (state === "uploading") {
262	        const pct = entry.repos[0]?.progress_pct;
263	        const rate = entry.repos[0]?.rate_kb;
264	        let label = "Uploading";
265	        if (pct !== null && pct !== undefined) label += " " + pct + "%";
266	        if (rate !== null && rate !== undefined && rate > 0) label += " · " + rate + " KB/s";
267	        return label;
268	      }
269	      if (state === "downloading") return "Downloading";
270	      if (state === "error") return "Error: " + (entry.repos[0]?.error || "unknown");
271	      if (state === "waiting") return "Waiting to sync";
272	      if (!state) return "Starting up…";
273	      return state;
274	    }
275	
276	    function renderCard(lib, data) {
277	      const bodyEl   = document.getElementById("body-" + lib.id);
278	      const seenEl   = document.getElementById("seen-" + lib.id);
279	
280	      if (!data) {
281	        seenEl.textContent = "No report received";
282	        seenEl.className = "last-seen stale";
283	        bodyEl.innerHTML = '<div class="no-data">Container has not reported in yet.</div>';
284	        return;
285	      }
286	
287	      const stale   = data.stale;
288	      const secsAgo = data.seconds_ago;
289	      seenEl.textContent = "Last seen: " + ago(secsAgo);
290	      seenEl.className   = "last-seen" + (stale ? " stale" : "");
291	
292	      const repo  = (data.repos && data.repos[0]) || null;
293	      const state = repo ? repo.state : null;
294	      const cls   = badgeClass(state, stale);
295	      const label = badgeLabel(data, state, stale);
296	
297	      let progressBar = "";
298	      if (!stale && state === "uploading" && repo && repo.progress_pct !== null) {
299	        progressBar = `<div class="progress-bar-wrap">
300	          <div class="progress-bar" style="width:${repo.progress_pct}%"></div>
301	        </div>`;
302	      }
303	
304	      const lastIngest = data.last_ingest_at
305	        ? new Date(data.last_ingest_at).toLocaleString()
306	        : "—";
307	
308	      bodyEl.innerHTML = `
309	        <div class="status-badge ${cls}">
310	          <span class="dot ${cls}"></span>
311	          ${label}
312	        </div>
313	        ${progressBar}
314	        <div class="meta-grid">
315	          <div class="meta-item">
316	            <label>Daemon</label>
317	            <div class="val">${data.daemon_alive ? "Running (PID " + data.daemon_pid + ")" : "Not running"}</div>
318	          </div>
319	          <div class="meta-item">
320	            <label>Staging files</label>
321	            <div class="val">${fmtFiles(data.staging_files)}</div>
322	          </div>
323	          <div class="meta-item">
324	            <label>Ingest window</label>
325	            <div class="val">${fmtIngestDays(data.ingest_days)}</div>
326	          </div>
327	          <div class="meta-item">
328	            <label>Last ingest</label>
329	            <div class="val">${lastIngest}</div>
330	          </div>
331	        </div>
332	      `;
333	    }
334	
335	    async function refresh() {
336	      try {
337	        const resp = await fetch("{{ url_for('api_status_data') }}");
338	        if (!resp.ok) return;
339	        const data = await resp.json();
340	        LIBRARIES.forEach(lib => {
341	          // match by container_id (matches lib.id) or by library_uuid
342	          const entry = data[lib.id]
343	            || Object.values(data).find(e => e.library_uuid === lib.uuid)
344	            || null;
345	          renderCard(lib, entry);
346	        });
347	        document.getElementById("refresh-note").textContent =
348	          "Last refreshed: " + new Date().toLocaleTimeString();
349	      } catch (e) {
350	        document.getElementById("refresh-note").textContent = "Refresh failed — retrying…";
351	      }
352	    }
353	
354	    refresh();
355	    setInterval(refresh, 10000);
356	  </script>
357	</body>
358	</html>
